// ── Lookup maps — O(1) code → name resolution ──────────────────
// These are computed once at module load, no data duplication.

// REGIONS_MAP["AT11"] → { id: "AT11", name: "Burgenland", country: "AT", countryName: "Austria" }
export const REGIONS_MAP = Object.fromEntries(REGIONS.map(r => [r.id, r]));

// COUNTRIES_MAP["AT"] → "Austria"
export const COUNTRIES_MAP = Object.fromEntries(COUNTRIES.map(c => [c.code, c.name]));

// INDICATORS_LABELS["107a_Unempl"] → "Unemployment rate — total"
export const INDICATORS_LABELS = Object.fromEntries(
  Object.entries(INDICATORS_META).map(([code, meta]) => [code, meta.name])
);

// Helper: get region name by code, with fallback
export function getRegionName(code) {
  return REGIONS_MAP[code]?.name ?? code;
}

// Helper: get country name by code, with fallback
export function getCountryName(code) {
  return COUNTRIES_MAP[code] ?? code;
}

// Helper: get indicator label by code, with fallback
export function getIndicatorLabel(code) {
  return INDICATORS_LABELS[code] ?? code;
}
